import React from 'react';

type PageLayoutProps = {
  children: React.ReactNode;
  className?: string;
  contentClassName?: string;
};

const PageLayout: React.FC<PageLayoutProps> = ({ children, className = '', contentClassName = '' }) => {
  return (
    <div className={`w-full px-6 md:px-12 py-16 md:py-24 ${className}`}>
      <div className={`mx-auto w-full max-w-[1280px] space-y-20 ${contentClassName}`}>
        {children}
      </div>
    </div>
  );
};

export default PageLayout;
